<?php require_once __DIR__ . '/../includes/auth.php'; require_admin();
$counts = db()->query("SELECT (SELECT COUNT(*) FROM articles) AS articles, (SELECT COUNT(*) FROM submissions WHERE status='new') AS submissions, (SELECT COUNT(*) FROM media_uploads) AS media")->fetch();
$articles = db()->query("SELECT a.id,a.title,a.status,a.updated_at,u.name AS author FROM articles a LEFT JOIN users u ON u.id=a.author_id ORDER BY a.updated_at DESC LIMIT 10")->fetchAll();
require __DIR__ . '/partials/header.php'; ?>
<div class="admin-heading"><div><p class="eyebrow">Dashboard</p><h1>Good to see you, <?= e(admin_user()['name']) ?>.</h1></div><a class="button" href="<?=url('admin/article.php')?>">Create article <span>+</span></a></div>
<div class="stats"><div><strong><?=e((string)$counts['articles'])?></strong><span>Articles</span></div><div><strong><?=e((string)$counts['submissions'])?></strong><span>New submissions</span></div><div><strong><?=e((string)$counts['media'])?></strong><span>Media files</span></div></div>
<section class="admin-panel"><div class="panel-heading"><h2>Recent articles</h2><a href="<?=url('admin/articles.php')?>">See all</a></div><?php if(!$articles): ?><p>No articles yet. Your next local legend is waiting to be told.</p><?php else: ?><table><thead><tr><th>Title</th><th>Status</th><th>Updated</th><th></th></tr></thead><tbody><?php foreach($articles as $article): ?><tr><td><?=e($article['title'])?></td><td><span class="status <?=e($article['status'])?>"><?=e($article['status'])?></span></td><td><?=date('M j, Y',strtotime($article['updated_at']))?></td><td><a href="<?=url('admin/article.php?id='.$article['id'])?>">Edit</a></td></tr><?php endforeach;?></tbody></table><?php endif;?></section>
<?php require __DIR__ . '/partials/footer.php'; ?>
